import{_ as a,o as r,c as o,ae as i}from"./chunks/framework.B6gjLfeO.js";const k=JSON.parse('{"title":"Deep Linking Reference for Marketers","description":"","frontmatter":{"title":"Deep Linking Reference for Marketers","slug":"marketer-deep-link-reference"},"headers":[],"relativePath":"marketer-hub/marketer-deep-link-reference.md","filePath":"marketer-hub/marketer-deep-link-reference.md"}'),n={name:"marketer-hub/marketer-deep-link-reference.md"};function t(l,e,p,s,h,d){return r(),o("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This article includes the information that a marketer needs to create deep links using Branch.</p><h2 id="how-deep-linking-works" tabindex="-1">How deep linking works <a class="header-anchor" href="#how-deep-linking-works" aria-label="Permalink to &quot;How deep linking works&quot;">​</a></h2><p>Deep linking is a technology that allows URLs to send users directly to specific content within a mobile app, rather than just the app&#39;s home screen. Branch is a platform that specializes in making this seamless across all devices and scenarios. Our links work whether the user has the app installed or not, and they handle the complexity of routing users to the right place on iOS, Android, or web.</p><p>Branch supports deferred deep linking. With this, if someone needs to install the app first, the deep link remembers where they were trying to go and takes them to that specific content once the app opens.</p><h2 id="how-branch-links-work" tabindex="-1">How Branch Links work <a class="header-anchor" href="#how-branch-links-work" aria-label="Permalink to &quot;How Branch Links work&quot;">​</a></h2><p>App links are deep links that take users to specific pages in your app. Web links are web-only Short Links that work everywhere. Web and app links look the same (yourbrand.com/slug or yourbrand.app.link/slug) depending on if you choose to use a custom domain or a Branch-provided <a href="http://app.link" target="_blank" rel="noreferrer">app.link</a> domain.</p><p>Ad Links are deep links that provide you with full attribution and analytics across email, referrals, paid advertising, social, organic search, and desktop-to-mobile. If you are running paid advertising campaigns, you&#39;ll want to create an Ad Link so we can accurately attribute resulting app conversions to the appropriate advertising partner. Branch Ad Links support Android App Links, and iOS Universal Links, as well as web and app conversions.</p><h3 id="expected-behavior-for-web-links" tabindex="-1">Expected behavior for web links <a class="header-anchor" href="#expected-behavior-for-web-links" aria-label="Permalink to &quot;Expected behavior for web links&quot;">​</a></h3><p>If your end user does not have your app installed, or if you don’t have an app, the link will open in their default web browser. If they do have your app downloaded, the link will open in your app through an in-app web view.</p><p>Read our Create Web Links article to learn more about app links.</p><h3 id="expected-behavior-for-app-links" tabindex="-1">Expected behavior for app links <a class="header-anchor" href="#expected-behavior-for-app-links" aria-label="Permalink to &quot;Expected behavior for app links&quot;">​</a></h3><p>If your end user has your app installed, the App Link will deep link to the specific app page you’ve chosen. If they do not have your app installed, they will taken to the redirect destination for non-app users which can be configured as a web page, a Branch Deepview, or the app store listing to download the app.</p><h3 id="expected-behavior-for-ad-links" tabindex="-1">Expected behavior for Ad Links <a class="header-anchor" href="#expected-behavior-for-ad-links" aria-label="Permalink to &quot;Expected behavior for Ad Links&quot;">​</a></h3><h3 id="long-links" tabindex="-1">Long links <a class="header-anchor" href="#long-links" aria-label="Permalink to &quot;Long links&quot;">​</a></h3><p>Long links can be created without a network call to Branch. Long links need <a href="./creating-a-deep-link.html#configure-deep-links">link data</a> to be added as a query string. Be sure to URI encode any URLs in the link.</p><ul><li>Existing link example: <code>https://example.app.link/fzmLEhobLD?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code> or</li><li>Dynamic link example: <code>https://example.app.link/?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code> .</li></ul><p>Long links need a <code>/a/</code> and a <a href="./profile-settings.html">Branch Key</a> if you use a custom domain.</p><ul><li>Existing link example: <code>https://link.example.com/5NPh/p4M09KRLrD?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code></li><li>Dynamic link example: <code>https://link.example.com/a/key_live_kaFuWw8WvY7yn1d9yYiP8gokwqjV0Swt?foo=bar&amp;baz=456&amp;$fallback_url=https%3A%2F%2Fbranch.io%2F</code></li></ul><p>When adding <code>tags</code> to a dynamic link, enter each tag separately. For example: <code>https://example.app.link/?foo=bar&amp;~tags=tag1&amp;~tags=tag2</code></p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>You can set up a custom domain in Branch or you can use the Branch-provided app.link domain. If you want in-app web views to work, you must have the latest version of the Branch SDK installed.</p><h3 id="set-up-a-custom-domain-optional" tabindex="-1">Set up a custom domain (optional) <a class="header-anchor" href="#set-up-a-custom-domain-optional" aria-label="Permalink to &quot;Set up a custom domain (optional)&quot;">​</a></h3><p>You can set up a custom domain (for example, link.yourbrand.com) in Branch. Read our <a href="./advanced-settings-configuration.html">Advanced Settings &amp; Changing Link Domain</a> article to learn how.</p><p>After you set up your custom domain, you can use it to create branded web Short Links.</p><h3 id="set-up-app-integration" tabindex="-1">Set up app integration <a class="header-anchor" href="#set-up-app-integration" aria-label="Permalink to &quot;Set up app integration&quot;">​</a></h3><p>You must have the latest version of the Branch SDK (latest update May 15, 2025) installed for app links to work. This setup requires a developer.</p><p>Read the following articles to learn more:</p><ul><li><a href="https://help.branch.io/developers-hub/docs/native-sdks-overview" target="_blank" rel="noreferrer">Branch SDK Overview</a></li><li><a href="https://help.branch.io/developers-hub/docs/ios-sdk-overview" target="_blank" rel="noreferrer">Branch iOS SDK Overview</a></li><li><a href="https://help.branch.io/developers-hub/docs/android-sdk-overview" target="_blank" rel="noreferrer">Branch Android SDK Overview</a></li></ul><h2 id="validate-deep-link-behavior" tabindex="-1">Validate deep link behavior <a class="header-anchor" href="#validate-deep-link-behavior" aria-label="Permalink to &quot;Validate deep link behavior&quot;">​</a></h2><p>Use the <a href="./link-validator.html">Link Validator</a> to view the expected and actual behavior of your links=.</p>',31)])])}const u=a(n,[["render",t]]);export{k as __pageData,u as default};
